question:
次のコードの出力順として正しいのはどれか？

console.log("A");
setTimeout(function() { console.log("B"); }, 1000);
console.log("C");

次のコードで「Hello!」が出力されるのはいつか？

setTimeout(function() {
  console.log("Hello!");
}, 500);
console.log("Start");

次のコードの実行結果として正しいのはどれか？

function greet(name) {
  console.log("こんにちは、" + name + "！");
}
function execute(fn, value) {
  fn(value);
}
execute(greet, "田中");

次のコードでボタンをクリックしたとき、コールバック関数はどのタイミングで実行されるか？

button.addEventListener("click", function() {
  console.log("クリックされた！");
});

次のコードの出力順として正しいのはどれか？

console.log("1");
setTimeout(function() {
  console.log("2");
}, 0);
console.log("3");

エラーファーストコールバックパターンで、コールバック内の正しい処理の流れはどれか？

readFile("data.txt", function(err, data) {
  // ここに書く
});

次のコードの実行結果として正しいのはどれか？

[10, 20, 30].forEach(function(value, index) {
  console.log(index + ": " + value);
});

次のコードの実行結果として正しいのはどれか？

let result = null;
setTimeout(function() {
  result = "完了";
}, 1000);
console.log(result);

次のコードの実行結果として正しいのはどれか？

const nums = [1, 2, 3, 4, 5];
const result = nums.filter(function(n) {
  return n % 2 === 0;
});
console.log(result);

次のコードで、コールバック関数の引数 e（イベントオブジェクト）はどこから渡されるか？

document.addEventListener("keydown", function(e) {
  console.log(e.key);
});

次のコードで setTimeout 内のコールバックから this.name が「田中」を正しく出力するために適切な修正はどれか？

const person = {
  name: "田中",
  greet: function() {
    setTimeout(function() {
      console.log(this.name); // ここが undefined になる
    }, 1000);
  }
};
person.greet();

次のコードの出力順として正しいのはどれか？

setTimeout(function() { console.log("A"); }, 100);
setTimeout(function() { console.log("B"); }, 0);
console.log("C");

次のコードで、setTimeout 内で発生したエラーを外側の try-catch で捕捉できるか？

try {
  setTimeout(function() {
    throw new Error("非同期エラー");
  }, 1000);
} catch (e) {
  console.log("キャッチ:", e.message);
}
